import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const h=JSON.parse('{"title":"Encryption","description":"","frontmatter":{},"headers":[],"relativePath":"guide/encryption.md","filePath":"guide/encryption.md","lastUpdated":1772600914000}'),s={name:"guide/encryption.md"};function n(i,e,l,p,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-label="Permalink to &quot;Encryption&quot;">​</a></h1><p>getbased stores all your data locally in your browser — nothing is uploaded to any server (except what you deliberately send to an AI provider). On top of that, you can enable encryption at rest to protect your data with a passphrase.</p><h2 id="local-storage" tabindex="-1">Local Storage <a class="header-anchor" href="#local-storage" aria-label="Permalink to &quot;Local Storage&quot;">​</a></h2><p>All your lab data, context cards, notes, supplements, and settings live in your browser&#39;s <strong>localStorage</strong> and <strong>IndexedDB</strong>. No account is required. No data is synced to the cloud. Clearing your browser data will erase getbased data, so use the export and backup features regularly.</p><h2 id="encryption-at-rest" tabindex="-1">Encryption at Rest <a class="header-anchor" href="#encryption-at-rest" aria-label="Permalink to &quot;Encryption at Rest&quot;">​</a></h2><p>When you set a passphrase in <strong>Settings → Security</strong>, your data is encrypted before being written to localStorage using:</p><ul><li><strong>AES-256-GCM</strong> — authenticated encryption that protects both confidentiality and integrity</li><li><strong>PBKDF2</strong> key derivation — your passphrase is never stored directly; it is stretched into a cryptographic key</li></ul><p>When you open getbased, you are prompted for your passphrase to decrypt and load your data. Without the correct passphrase, the data is unreadable.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>There is no passphrase recovery. If you forget your passphrase, your data cannot be decrypted. Make sure to export a plaintext JSON backup before enabling encryption, or store your passphrase somewhere safe.</p></div><h3 id="passphrase-requirements" tabindex="-1">Passphrase Requirements <a class="header-anchor" href="#passphrase-requirements" aria-label="Permalink to &quot;Passphrase Requirements&quot;">​</a></h3><p>Passphrases must meet all four rules:</p><ul><li>At least <strong>8 characters</strong></li><li>At least <strong>1 lowercase</strong> letter</li><li>At least <strong>1 uppercase</strong> letter</li><li>At least <strong>1 special character</strong> (<code>!@#$%^&amp;*</code> etc.)</li></ul><p>A live strength meter with a color-coded bar and checklist shows your progress as you type. The encryption button is disabled until all rules pass.</p><h3 id="encryption-nudge" tabindex="-1">Encryption Nudge <a class="header-anchor" href="#encryption-nudge" aria-label="Permalink to &quot;Encryption Nudge&quot;">​</a></h3><p>After your first PDF import, getbased shows a one-time prompt suggesting you enable encryption. This is a reminder, not a requirement — you can dismiss it and enable encryption later from Settings.</p><h2 id="three-backup-layers" tabindex="-1">Three Backup Layers <a class="header-anchor" href="#three-backup-layers" aria-label="Permalink to &quot;Three Backup Layers&quot;">​</a></h2><p>getbased protects your data with three independent backup mechanisms:</p><h3 id="_1-indexeddb-auto-backup" tabindex="-1">1. IndexedDB Auto-Backup <a class="header-anchor" href="#_1-indexeddb-auto-backup" aria-label="Permalink to &quot;1. IndexedDB Auto-Backup&quot;">​</a></h3><p>Automatic in-browser snapshots happen in the background:</p><ul><li>A backup is triggered 60 seconds after any data change (debounced — rapid changes only trigger one backup)</li><li>Up to <strong>5 snapshots</strong> are stored; the oldest is pruned when a new one is added</li><li>Each snapshot includes all your lab entries, context cards, notes, supplements, cycle data, and per-profile preferences</li></ul><p>Go to <strong>Settings → Data → Backup &amp; Restore</strong> to see your saved snapshots. Each entry shows the date and time it was created. Click <strong>Restore</strong> next to any snapshot to roll back.</p><h3 id="_2-folder-backup" tabindex="-1">2. Folder Backup <a class="header-anchor" href="#_2-folder-backup" aria-label="Permalink to &quot;2. Folder Backup&quot;">​</a></h3><p>Auto-save to a local folder on your computer — Proton Drive, Dropbox, NAS, or any location you trust. This uses the File System Access API (Chromium browsers only). See <a href="./folder-backup.html">Folder Backup</a> for full details.</p><h3 id="_3-manual-json-export" tabindex="-1">3. Manual JSON Export <a class="header-anchor" href="#_3-manual-json-export" aria-label="Permalink to &quot;3. Manual JSON Export&quot;">​</a></h3><p>Download a plaintext copy of all your data at any time. Store it somewhere safe (a password manager, encrypted drive, or offline backup). See <a href="./json-export-import.html">JSON Export &amp; Import</a> for details.</p><h3 id="backup-reminder" tabindex="-1">Backup Reminder <a class="header-anchor" href="#backup-reminder" aria-label="Permalink to &quot;Backup Reminder&quot;">​</a></h3><p>If you haven&#39;t configured folder backup and haven&#39;t manually exported in over 30 days, getbased shows a gentle reminder nudge. You can snooze it for another 30 days or set up folder backup to dismiss it permanently.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can restore a backup even without a passphrase configured — backups follow the same encryption state as your main data at the time they were created.</p></div><h2 id="what-is-and-is-not-encrypted" tabindex="-1">What Is and Is Not Encrypted <a class="header-anchor" href="#what-is-and-is-not-encrypted" aria-label="Permalink to &quot;What Is and Is Not Encrypted&quot;">​</a></h2><p>When encryption is enabled, the following are encrypted:</p><ul><li>All imported lab data (entries, notes, supplements, cycle data, context cards)</li><li>Chat conversation history</li><li>Custom personality settings</li></ul><p>Settings such as your chosen AI provider and theme are stored in plaintext (they contain no health data).</p><p>AI API requests are always transmitted to your chosen provider over HTTPS, regardless of your encryption setting. Your provider&#39;s privacy policy governs how they handle those requests.</p>',33)])])}const y=a(s,[["render",n]]);export{h as __pageData,y as default};
